import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { login } from "../api/auth";

const Login = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const redirectTo = location.state?.from?.pathname || "/dashboard";
  const [form, setForm] = useState({ email: "", password: "" });
  const [status, setStatus] = useState({ loading: false, error: "" });

  const handleChange = (event) => {
    setForm((prev) => ({ ...prev, [event.target.name]: event.target.value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setStatus({ loading: true, error: "" });
    try {
      await login({ email: form.email, password: form.password });
      navigate(redirectTo, { replace: true });
    } catch (error) {
      setStatus({ loading: false, error: "Invalid email or password." });
    }
  };
  return (
    <div className="auth-page">
      <section className="auth-hero">
        <div className="auth-hero__badge">SmartSpend</div>
        <h1>Expense clarity for fast-moving teams.</h1>
        <p>
          Watch approvals, spot anomalies, and move budgets faster with a
          real-time spend command center.
        </p>
        <div className="auth-hero__stats">
          <div className="card stat-card">
            <div className="stat-card__label">Monthly spend</div>
            <div className="stat-card__value">$482K</div>
            <div className="stat-card__label">-6.4% vs last month</div>
          </div>
          <div className="card stat-card">
            <div className="stat-card__label">Open approvals</div>
            <div className="stat-card__value">19</div>
            <div className="stat-card__label">3 urgent</div>
          </div>
        </div>
      </section>
      <section className="auth-card">
        <h2>Welcome back</h2>
        <form className="form" onSubmit={handleSubmit}>
          <div className="field">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              name="email"
              type="email"
              placeholder="you@company.com"
              value={form.email}
              onChange={handleChange}
              required
            />
          </div>
          <div className="field">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              name="password"
              type="password"
              placeholder="••••••••"
              value={form.password}
              onChange={handleChange}
              required
            />
          </div>
          {status.error ? <div className="alert">{status.error}</div> : null}
          <button className="button" type="submit" disabled={status.loading}>
            {status.loading ? "Signing in..." : "Sign in"}
          </button>
        </form>
        <div className="auth-links">
          <Link to="/register">Create account</Link>
          <Link to="/dashboard">Skip for now</Link>
        </div>
      </section>
    </div>
  );
};

export default Login;
